import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-download.IKA_571t.js";const a=JSON.parse(`{"title":"Налаштування IntelliJ IDEA","description":"Покрокова інструкція з налаштування IntelliJ IDEA для створення модів Fabric.","frontmatter":{"title":"Налаштування IntelliJ IDEA","description":"Покрокова інструкція з налаштування IntelliJ IDEA для створення модів Fabric.","authors":["2xsaiko","Andrew6rant","asiekierka","Daomephsta","dicedpixels","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","TelepathicGrunt"],"authors-nogithub":["siglong"],"prev":{"text":"Налаштування вашого IDE","link":"../setting-up"},"next":{"text":"Відкриття проєкту в IntelliJ IDEA","link":"./opening-a-project"},"resources":{"https://www.jetbrains.com/idea/download/":"Завантажити IntelliJ IDEA з JetBrains","https://www.jetbrains.com/help/idea/getting-started.html":"Початок роботи з IntelliJ IDEA","https://plugins.jetbrains.com/plugin/8327-minecraft-development":"Плаґін Development Plugin — JB Marketplace"},"files":[]},"headers":[],"relativePath":"uk_ua/develop/getting-started/intellij-idea/setting-up.md","filePath":"translated/uk_ua/develop/getting-started/intellij-idea/setting-up.md","lastUpdated":1774518827000}`);var o={name:`uk_ua/develop/getting-started/intellij-idea/setting-up.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Налаштування IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “Налаштування IntelliJ IDEA”">​</a></h1><div class="info custom-block"><p class="custom-block-title">ПЕРЕДУМОВИ</p><p>Спершу переконайтеся, що ви <a href="./../setting-up#install-jdk-21">встановили JDK</a>.</p></div><h2 id="installing-intellij-idea" tabindex="-1">Установлення IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “Установлення IntelliJ IDEA”">​</a></h2><p>Якщо у вас не встановлено IntelliJ IDEA, ви можете завантажити його з <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">офіційного сайту</a> — дотримуйтеся вказівок зі встановлення для вашої операційної системи.</p><p><img src="/assets/develop/getting-started/idea-download.png" alt="Запит на завантаження IntelliJ IDEA" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">Установлення плаґіна «Minecraft Development» <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “Установлення плаґіна «Minecraft Development»”">​</a></h2><p>Плаґін Minecraft Development підтримує модифікацію за допомогою Fabric, і це найважливіший плаґін для встановлення.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Попри те, що цей плаґін не є абсолютно необхідним, він може значно полегшити модифікацію за допомогою Fabric — вам слід подумати про його встановлення.</p></div><p>Ви можете встановити його, відкривши IntelliJ IDEA, а потім перейшовши до <strong>File</strong> &gt; <strong>Settings…</strong> &gt; <strong>Plugins</strong> &gt; вкладка <strong>Marketplace</strong>, потім знайдіть <code>Minecraft Development</code> у рядку пошуку та натисніть кнопку <strong>Install</strong>.</p><p>Крім того, ви можете завантажити його зі <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">сторінки плаґінів</a>, а потім установити, перейшовши до <strong>File</strong> &gt; <strong>Settings</strong> &gt; <strong>Plugins</strong> &gt; <strong>Install Plugin From Disk</strong>.</p><h3 id="about-creating-a-project" tabindex="-1">Про створення проєкту <a class="header-anchor" href="#about-creating-a-project" aria-label="Permalink to “Про створення проєкту”">​</a></h3><p>Хоча за допомогою цього плаґіна можна створити проєкт, це не рекомендується, оскільки шаблони часто застаріли. Натомість спробуйте виконати <a href="./../creating-a-project">створення проєкту</a>, щоб скористатися генератором шаблона мода Fabric.</p>`,12)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};